UPDATE public.garden_import_queue SET payload = '{"species": "Aloe Vera", "species_slug": "aloe-vera", "varieties": [{"name": "Aloe barbadensis Miller (True Aloe Vera)", "slug": "aloe-barbadensis-miller-true-aloe-vera", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Arabian Peninsula, cultivated since ancient times (2000+ years)", "traits": "Thick, fleshy, grey-green to green leaves in rosette formation, 50-100cm tall. White flecks may appear on young leaves but fade with maturity. Serrated margins with small white teeth. Stemless or very short-stemmed.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Widely available throughout Brisbane nurseries, Bunnings, garden centers, and online marketplaces (Gumtree, eBay). Price range: $3-20 depending on size.", "sort_order": 0}, {"name": "Aloe barbadensis ''Stockton''", "slug": "aloe-barbadensis-stockton", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Selected variety of A. barbadensis Miller, identified by Rodney Stockton for superior medicinal qualities", "traits": "Pure green leaves without spots at maturity (young plants show white spots that fade). Slightly thicker and wider leaves at base than standard variety.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "", "sort_order": 1}, {"name": "Aloe vera var. chinensis (Chinese Aloe, Spotted Aloe)", "slug": "aloe-vera-var-chinensis-chinese-aloe-spotted-aloe", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Variety of A. barbadensis, cultivated extensively in China and India since ancient times", "traits": "Smaller than true aloe (up to 45cm). Grey-green leaves with persistent white spots that remain longer than standard variety. More compact, fan-shaped offsets. Leaves take on brownish-red hue in intense sun.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Available in Brisbane but often not la