UPDATE public.garden_import_queue SET payload = '{"species": "Asparagus", "species_slug": "asparagus", "varieties": [{"name": "Mary Washington 🏆", "slug": "mary-washington", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "USA, 1919. Developed by Dr. J.B. Norton, USDA, from the Washington strain for rust resistance.", "traits": "Medium to large spears, deep green color with pale purple tips and bracts, 15-20cm long, 1-2cm diameter.", "flesh_fruit": "", "yield_notes": "Moderate to good. Mix of male/female plants (approximately 50/50), female plants reduce overall productivity.", "growing_notes": "", "availability": "Widely available in Australia - Bunnings, nurseries throughout Queensland, online seed suppliers (Eden Brothers, The Seed Collection Australia).", "sort_order": 0}, {"name": "Conover''s Colossal (Connovar''s Colossal) 🏆", "slug": "conover-s-colossal-connovar-s-colossal", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "USA, 1868. Developed by S.B. Conover, New York produce merchant. One of the oldest heirloom varieties still in cultivation.", "traits": "Very thick spears (up to 3.8cm diameter), stumpy stems, dark green tinged with purple, pointed bud tips.", "flesh_fruit": "", "yield_notes": "Very high yields for a non-hybrid variety. Heavy cropper with graceful feathery foliage.", "growing_notes": "", "availability": "Available as seeds in Australia - Baker Creek Heirloom Seeds, Premier Seeds Direct, online heirloom seed suppliers.", "sort_order": 1}, {"name": "UC-157 (UC 157 F2) 🌱", "slug": "uc-157-uc-157-f2", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "USA, 1978. University of California, Riverside. Developed for warm climate production.", "traits": "Pale green spears, medium-large diameter, smooth texture, tight tips, uniform stalks, 15-23cm long.", "flesh_fruit": "", "yield_notes": "Exceptionally high. Male and female plants (standard hybrid), but highly productive.", "growing_notes": "", "availability": "Available in Australia - Mountain Valley Growers (pots), True Leaf Market (seeds), select Australian seed suppliers.", "sort_order": 2}, {"name": "UC-72 (Mary''s Granddaughter)", "slug": "uc-72-mary-s-granddaughter", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "USA, UC Davis/Berkeley. Mary Washington improvement for heat tolerance.", "traits": "Dark green spears, fairly compact heads, slightly larger than Mary Washington, 15-30cm long, 1.25cm diameter.", "flesh_fruit": "", "yield_notes": "Heavy yields after establishment. Open-pollinated with male/female mix, but very productive.", "growing_notes": "", "availability": "Available in Australia - True Leaf Market, Eden Brothers, David''s Garden Seeds, St. Clare Heirloom Seeds, Premier Seeds Direct.", "sort_order": 3}, {"name": "Atlas F1", "slug": "atlas-f1", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "USA, 1980s. Walker Brothers, New Jersey. California x Eastern US male hybrid breeding program.", "traits": "Dark green smooth spears with slight purple at tips and butt, medium to large diameter, cylindrical shape, 18-23cm, tightly headed.", "flesh_fruit": "", "yield_notes": "Very high. All-male hybrid, 20-50% higher yielding than UC-157. Vigorous early variety.", "growing_notes": "", "availability": "", "sort_order": 4}, {"name": "Apollo F1", "slug": "apollo-f1", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "USA, 1984. California female x Eastern US male breeding program.", "traits": "Dark green spears with tight purple tips, ends and bracts, medium to large diameter, cylindrical shape with slight taper, smooth appearance.", "flesh_fruit": "", "yield_notes": "Very high. All-male hybrid, early maturing, 25-50% yield increase over UC-157.", "growing_notes": "", "availability": "Available in Australia - Urban Farmer, specialty asparagus suppliers, international nurseries.", "sort_order": 5}, {"name": "Grande Hybrid F1", "slug": "grande-hybrid-f1", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "USA, California breeding program for warm climate production.", "traits": "Green spears, medium-large diameter, uniform appearance.", "flesh_fruit": "", "yield_notes": "High yields with good consistency throughout season.", "growing_notes": "", "availability": "Limited in Australia - Gurney''s (US), international suppliers, may require import or specialty order.", "sort_order": 6}, {"name": "Jersey Giant F1", "slug": "jersey-giant-f1", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "USA, 1980s. Rutgers University, New Jersey breeding program. NOTE: Breeding discontinued, limited remaining stock.", "traits": "Thick meaty green spears with purple bracts, 18-23cm long, very uniform.", "flesh_fruit": "", "yield_notes": "Very high. All-male hybrid (mostly male), produces up to 2x yield of standard varieties.", "growing_notes": "", "availability": "", "sort_order": 7}, {"name": "Jersey Knight F1", "slug": "jersey-knight-f1", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "USA, 1980s. Rutgers University, New Jersey. NOTE: Breeding discontinued, limited remaining stock.", "traits": "Green spears with purple bracts, large diameter, best spear quality of Jersey hybrids, 18-25cm long.", "flesh_fruit": "", "yield_notes": "Very high. Mostly male plants, produces 3-4x more than standard varieties.", "growing_notes": "", "availability": "", "sort_order": 8}, {"name": "Jersey Supreme F1", "slug": "jersey-supreme-f1", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "USA, Rutgers University, New Jersey. Latest of Jersey series. NOTE: Breeding discontinued.", "traits": "Green spears, early maturing, uniform medium to large diameter.", "flesh_fruit": "", "yield_notes": "High. All-male variety, produces spears earlier in season.", "growing_notes": "", "availability": "VERY LIMITED - Variety discontinued. Final remaining stock at select retailers. Not recommended for new plantings.", "sort_order": 9}, {"name": "Millennium (Guelph Millennium) F1", "slug": "millennium-guelph-millennium-f1", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Canada, developed by Prof. David Wolyn, University of Guelph, Ontario. Released early 2000s.", "traits": "Pure solid green spears with purple bracts (moderate anthocyanin), thick tender straight spears, cylindrical uniform size, 18-25cm.", "flesh_fruit": "", "yield_notes": "Very high and consistent. All-male hybrid (100%), highly productive, equals Jersey varieties at maturity. Trials in Michigan showed 2094 lbs/acre vs Jersey Giant 1287 lbs/acre. Royal Horticultural Society Award of Garden Merit.", "growing_notes": "", "availability": "Available in Australia - Stark Brothers, Burpee, Nourse Farms, Veseys, West Coast Seeds, international suppliers. Good availability.", "sort_order": 10}, {"name": "Spartacus F1", "slug": "spartacus-f1", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Modern hybrid bred to replace Jersey varieties.", "traits": "Green spears with purple tips and bracts, medium size, straight, long.", "flesh_fruit": "", "yield_notes": "High yields. All-male hybrid.", "growing_notes": "", "availability": "Available internationally, limited in Australia, may require import from specialty suppliers.", "sort_order": 11}, {"name": "Purple Passion F1 🧬", "slug": "purple-passion-f1", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Bred from Italian heirloom ''Violet di Albenga'' (natural genetic mutation), open-pollinated purple variety.", "traits": "Deep purple spears (color fades to green when cooked), attractive appearance, purple tips and bracts.", "flesh_fruit": "", "yield_notes": "Moderate to good. Male and female plants (60% male), fewer but larger spears. Less productive than all-male green varieties but compensates with superior flavor.", "growing_notes": "", "availability": "", "sort_order": 12}, {"name": "Sweet Purple", "slug": "sweet-purple", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Italian heritage, cold-hardy purple variety.", "traits": "Bold purple color throughout, distinctive appearance.", "flesh_fruit": "", "yield_notes": "Good. Male and female plants mix.", "growing_notes": "", "availability": "Available - True Leaf Market (crowns), international suppliers, select Australian nurseries.", "sort_order": 13}, {"name": "Erasmus F1", "slug": "erasmus-f1", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "UK, 2012. First all-male purple hybrid asparagus, breakthrough variety.", "traits": "Deep purple spears with tight tips, mild color, brilliant purple when raw.", "flesh_fruit": "", "yield_notes": "Very high - revolutionary for purple varieties. All-male hybrid, yields 2-3x other purple varieties, on par with green varieties.", "growing_notes": "", "availability": "Limited in Australia - Gurney''s (US), European suppliers, specialty import may be required.", "sort_order": 14}, {"name": "Precoce D''Argenteuil (Early Argenteuil) 🏆", "slug": "precoce-d-argenteuil-early-argenteuil", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "France, 1885. Vilmorin-Andrieux selection from ''Giant Dutch Purple''. Argenteuil district near Paris, famous asparagus region since 1800s.", "traits": "Thick rose-purple spears when unblanched, attractive rosy pink tips, pale green when blanched (White Gold), 60-90cm tall at maturity.", "flesh_fruit": "", "yield_notes": "Good to very good. Male and female mix, but reliably productive.", "growing_notes": "", "availability": "", "sort_order": 15}, {"name": "Palmetto 🏆", "slug": "palmetto", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "USA, Southern states. Derived from Argenteuil selections. Pre-1900, long popular in the American South