UPDATE public.garden_import_queue SET payload = '{"species": "Basil", "species_slug": "basil", "varieties": [{"name": "Genovese Basil 🏆", "slug": "genovese-basil", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Genoa, Italy; traditional Italian variety, 100+ years old", "traits": "Large, dark green, slightly cupped leaves 7-10cm long. Strong, pungent aroma with sweet anise notes. Grows 45-60cm tall with bushy habit.", "flesh_fruit": "", "yield_notes": "High - produces 20+ harvests per plant with regular cutting. Can yield 6-8 bunches per square meter.", "growing_notes": "", "availability": "Widely available - Bunnings, nurseries throughout Brisbane/Queensland. Seed available from The Seed Collection, Diggers Club, Eden Seeds.", "sort_order": 0}, {"name": "Napoletano Basil (Lettuce Leaf) 🏆", "slug": "napoletano-basil-lettuce-leaf", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Naples, Italy; heirloom from Campania region, first offered by Franchi Sementi", "traits": "Massive crinkled leaves 10-15cm long, light green with blistered texture. Slow to bolt. Grows 50-60cm tall.", "flesh_fruit": "", "yield_notes": "Very high due to large leaf size. Single leaves can wrap sandwiches or be used as herb wraps.", "growing_notes": "", "availability": "Specialty seed suppliers - The Seed Collection, select Brisbane nurseries, Diggers Club, online from Eden Seeds.", "sort_order": 1}, {"name": "Sweet Basil (Ocimum basilicum)", "slug": "sweet-basil-ocimum-basilicum", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Native to tropical regions of Central Africa to Southeast Asia, cultivated 5000+ years", "traits": "Bright green oval leaves 5-8cm, tender, aromatic. Standard variety. Grows 30-45cm tall.", "flesh_fruit": "", "yield_notes": "High with regular harvesting. Produces continuously when kept from flowering.", "growing_notes": "", "availability": "Universally available - all Brisbane nurseries, Bunnings, supermarkets (living herbs), seed from all major suppliers.", "sort_order": 2}, {"name": "Mammoth Basil", "slug": "mammoth-basil", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Italian selection, bred for large leaf size", "traits": "Extra-large leaves up to 12cm, smooth, bright green. Vigorous growth to 60cm tall.", "flesh_fruit": "", "yield_notes": "Very high due to large leaf size. Excellent for pesto production.", "growing_notes": "", "availability": "Select Brisbane nurseries, The Seed Collection, online seed suppliers.", "sort_order": 3}, {"name": "Thai Basil (Siam Queen)", "slug": "thai-basil-siam-queen", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Southeast Asia (Thailand/Vietnam), Siam Queen developed 1997, AAS Award Winner", "traits": "Dark green serrated leaves, purple stems and flowers. Grows 45-60cm tall. Leaves 4cm long, 2cm wide. Late flowering.", "flesh_fruit": "", "yield_notes": "Very high. Siam Queen produces larger leaves than standard Thai basil. Slow bolting extends harvest.", "growing_notes": "", "availability": "Common in Brisbane - Asian grocery nurseries, Bunnings, Brisbane nurseries. Seed from The Seed Collection, West Coast Seeds, specialist suppliers.", "sort_order": 4}, {"name": "Lemon Basil (Ocimum × citriodorum)", "slug": "lemon-basil-ocimum-citriodorum", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Natural hybrid between O. basilicum and O. americanum, Southeast Asian origins", "traits": "Light green, narrow leaves with citrus scent. Compact growth 30-45cm. White flowers.", "flesh_fruit": "", "yield_notes": "Moderate to high. Fast-growing in warm conditions.", "growing_notes": "", "availability": "", "sort_order": 5}, {"name": "Lime Basil", "slug": "lime-basil", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Southeast Asia, similar to lemon basil", "traits": "Similar to lemon basil but with darker leaves and more compact growth. Small plant 25-40cm.", "flesh_fruit": "", "yield_notes": "Moderate. Compact size makes it ideal for container growing.", "growing_notes": "", "availability": "Select Brisbane nurseries, The Seed Collection, specialty suppliers.", "sort_order": 6}, {"name": "Dark Opal Basil 🏆", "slug": "dark-opal-basil", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "University of Connecticut, developed 1950s by John Scarchuk & Joseph Lent. AAS Award 1962", "traits": "Deep purple leaves, sometimes mottled. Lavender flowers. Grows 45-50cm tall. High anthocyanin content.", "flesh_fruit": "", "yield_notes": "Good. Slow to bolt. Recovers well after cutting.", "growing_notes": "", "availability": "Available Brisbane nurseries (seasonal), Bunnings, The Seed Collection, Eden Seeds, Diggers Club.", "sort_order": 7}, {"name": "Purple Ruffles Basil 🏆", "slug": "purple-ruffles-basil", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "USA, developed 1984 by Ted Torrey (Burpee). Cross of Green Ruffles × Dark Opal. AAS Award 1987", "traits": "Deeply serrated, ruffled dark purple leaves 7-8cm long. Striking ornamental appearance. Grows 45-60cm.", "flesh_fruit": "", "yield_notes": "Good. More pigmentation than Dark Opal. Resist bolting better than standard purple basil.", "growing_notes": "", "availability": "Specialty Brisbane nurseries, The Seed Collection, online seed suppliers, Diggers Club.", "sort_order": 8}, {"name": "Cinnamon Basil (Mexican Basil) 🏆", "slug": "cinnamon-basil-mexican-basil", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Mexico/Mediterranean region, cultivated for centuries. Also called Mexican Spice Basil", "traits": "Dark green leaves with purple veins, cinnamon-colored stems. Grows 45-90cm tall. Pink-purple flowers.", "flesh_fruit": "", "yield_notes": "Good. Vigorous in hot weather. Downy mildew resistant.", "growing_notes": "", 